import{_ as s,o as a,c as i,ai as o}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Migration Guide","description":"","frontmatter":{"summary":"Move (migrate) a OpenSoul install from one machine to another","read_when":["You are moving OpenSoul to a new laptop/server","You want to preserve sessions, auth, and channel logins (WhatsApp, etc.)"],"title":"Migration Guide"},"headers":[],"relativePath":"install/migrating.md","filePath":"install/migrating.md","lastUpdated":1771906665000}'),n={name:"install/migrating.md"};function t(r,e,l,p,d,h){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="migrating-opensoul-to-a-new-machine" tabindex="-1"><a class="header-anchor" href="#migrating-opensoul-to-a-new-machine">#</a> Migrating OpenSoul to a new machine</h1><p>This guide migrates a OpenSoul Gateway from one machine to another <strong>without redoing onboarding</strong>.</p><p>The migration is simple conceptually:</p><ul><li>Copy the <strong>state directory</strong> (<code>$OPENSOUL_STATE_DIR</code>, default: <code>~/.opensoul/</code>) — this includes config, auth, sessions, and channel state.</li><li>Copy your <strong>workspace</strong> (<code>~/.opensoul/workspace/</code> by default) — this includes your agent files (memory, prompts, etc.).</li></ul><p>But there are common footguns around <strong>profiles</strong>, <strong>permissions</strong>, and <strong>partial copies</strong>.</p><h2 id="before-you-start-what-you-are-migrating" tabindex="-1"><a class="header-anchor" href="#before-you-start-what-you-are-migrating">#</a> Before you start (what you are migrating)</h2><h3 id="_1-identify-your-state-directory" tabindex="-1"><a class="header-anchor" href="#_1-identify-your-state-directory">#</a> 1) Identify your state directory</h3><p>Most installs use the default:</p><ul><li><strong>State dir:</strong> <code>~/.opensoul/</code></li></ul><p>But it may be different if you use:</p><ul><li><code>--profile &lt;name&gt;</code> (often becomes <code>~/.opensoul-&lt;profile&gt;/</code>)</li><li><code>OPENSOUL_STATE_DIR=/some/path</code></li></ul><p>If you’re not sure, run on the <strong>old</strong> machine:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Look for mentions of <code>OPENSOUL_STATE_DIR</code> / profile in the output. If you run multiple gateways, repeat for each profile.</p><h3 id="_2-identify-your-workspace" tabindex="-1"><a class="header-anchor" href="#_2-identify-your-workspace">#</a> 2) Identify your workspace</h3><p>Common defaults:</p><ul><li><code>~/.opensoul/workspace/</code> (recommended workspace)</li><li>a custom folder you created</li></ul><p>Your workspace is where files like <code>MEMORY.md</code>, <code>USER.md</code>, and <code>memory/*.md</code> live.</p><h3 id="_3-understand-what-you-will-preserve" tabindex="-1"><a class="header-anchor" href="#_3-understand-what-you-will-preserve">#</a> 3) Understand what you will preserve</h3><p>If you copy <strong>both</strong> the state dir and workspace, you keep:</p><ul><li>Gateway configuration (<code>opensoul.json</code>)</li><li>Auth profiles / API keys / OAuth tokens</li><li>Session history + agent state</li><li>Channel state (e.g. WhatsApp login/session)</li><li>Your workspace files (memory, skills notes, etc.)</li></ul><p>If you copy <strong>only</strong> the workspace (e.g., via Git), you do <strong>not</strong> preserve:</p><ul><li>sessions</li><li>credentials</li><li>channel logins</li></ul><p>Those live under <code>$OPENSOUL_STATE_DIR</code>.</p><h2 id="migration-steps-recommended" tabindex="-1"><a class="header-anchor" href="#migration-steps-recommended">#</a> Migration steps (recommended)</h2><h3 id="step-0-—-make-a-backup-old-machine" tabindex="-1"><a class="header-anchor" href="#step-0-—-make-a-backup-old-machine">#</a> Step 0 — Make a backup (old machine)</h3><p>On the <strong>old</strong> machine, stop the gateway first so files aren’t changing mid-copy:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>(Optional but recommended) archive the state dir and workspace:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Adjust paths if you use a profile or custom locations</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -czf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensoul-state.tgz</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .opensoul</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -czf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensoul-workspace.tgz</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .opensoul/workspace</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>If you have multiple profiles/state dirs (e.g. <code>~/.opensoul-main</code>, <code>~/.opensoul-work</code>), archive each.</p><h3 id="step-1-—-install-opensoul-on-the-new-machine" tabindex="-1"><a class="header-anchor" href="#step-1-—-install-opensoul-on-the-new-machine">#</a> Step 1 — Install OpenSoul on the new machine</h3><p>On the <strong>new</strong> machine, install the CLI (and Node if needed):</p><ul><li>See: <a href="/docs/install/index">Install</a></li></ul><p>At this stage, it’s OK if onboarding creates a fresh <code>~/.opensoul/</code> — you will overwrite it in the next step.</p><h3 id="step-2-—-copy-the-state-dir-workspace-to-the-new-machine" tabindex="-1"><a class="header-anchor" href="#step-2-—-copy-the-state-dir-workspace-to-the-new-machine">#</a> Step 2 — Copy the state dir + workspace to the new machine</h3><p>Copy <strong>both</strong>:</p><ul><li><code>$OPENSOUL_STATE_DIR</code> (default <code>~/.opensoul/</code>)</li><li>your workspace (default <code>~/.opensoul/workspace/</code>)</li></ul><p>Common approaches:</p><ul><li><code>scp</code> the tarballs and extract</li><li><code>rsync -a</code> over SSH</li><li>external drive</li></ul><p>After copying, ensure:</p><ul><li>Hidden directories were included (e.g. <code>.opensoul/</code>)</li><li>File ownership is correct for the user running the gateway</li></ul><h3 id="step-3-—-run-doctor-migrations-service-repair" tabindex="-1"><a class="header-anchor" href="#step-3-—-run-doctor-migrations-service-repair">#</a> Step 3 — Run Doctor (migrations + service repair)</h3><p>On the <strong>new</strong> machine:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Doctor is the “safe boring” command. It repairs services, applies config migrations, and warns about mismatches.</p><p>Then:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="common-footguns-and-how-to-avoid-them" tabindex="-1"><a class="header-anchor" href="#common-footguns-and-how-to-avoid-them">#</a> Common footguns (and how to avoid them)</h2><h3 id="footgun-profile-state-dir-mismatch" tabindex="-1"><a class="header-anchor" href="#footgun-profile-state-dir-mismatch">#</a> Footgun: profile / state-dir mismatch</h3><p>If you ran the old gateway with a profile (or <code>OPENSOUL_STATE_DIR</code>), and the new gateway uses a different one, you’ll see symptoms like:</p><ul><li>config changes not taking effect</li><li>channels missing / logged out</li><li>empty session history</li></ul><p>Fix: run the gateway/service using the <strong>same</strong> profile/state dir you migrated, then rerun:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="footgun-copying-only-opensoul-json" tabindex="-1"><a class="header-anchor" href="#footgun-copying-only-opensoul-json">#</a> Footgun: copying only <code>opensoul.json</code></h3><p><code>opensoul.json</code> is not enough. Many providers store state under:</p><ul><li><code>$OPENSOUL_STATE_DIR/credentials/</code></li><li><code>$OPENSOUL_STATE_DIR/agents/&lt;agentId&gt;/...</code></li></ul><p>Always migrate the entire <code>$OPENSOUL_STATE_DIR</code> folder.</p><h3 id="footgun-permissions-ownership" tabindex="-1"><a class="header-anchor" href="#footgun-permissions-ownership">#</a> Footgun: permissions / ownership</h3><p>If you copied as root or changed users, the gateway may fail to read credentials/sessions.</p><p>Fix: ensure the state dir + workspace are owned by the user running the gateway.</p><h3 id="footgun-migrating-between-remote-local-modes" tabindex="-1"><a class="header-anchor" href="#footgun-migrating-between-remote-local-modes">#</a> Footgun: migrating between remote/local modes</h3><ul><li>If your UI (WebUI/TUI) points at a <strong>remote</strong> gateway, the remote host owns the session store + workspace.</li><li>Migrating your laptop won’t move the remote gateway’s state.</li></ul><p>If you’re in remote mode, migrate the <strong>gateway host</strong>.</p><h3 id="footgun-secrets-in-backups" tabindex="-1"><a class="header-anchor" href="#footgun-secrets-in-backups">#</a> Footgun: secrets in backups</h3><p><code>$OPENSOUL_STATE_DIR</code> contains secrets (API keys, OAuth tokens, WhatsApp creds). Treat backups like production secrets:</p><ul><li>store encrypted</li><li>avoid sharing over insecure channels</li><li>rotate keys if you suspect exposure</li></ul><h2 id="verification-checklist" tabindex="-1"><a class="header-anchor" href="#verification-checklist">#</a> Verification checklist</h2><p>On the new machine, confirm:</p><ul><li><code>opensoul status</code> shows the gateway running</li><li>Your channels are still connected (e.g. WhatsApp doesn’t require re-pair)</li><li>The dashboard opens and shows existing sessions</li><li>Your workspace files (memory, configs) are present</li></ul><h2 id="related" tabindex="-1"><a class="header-anchor" href="#related">#</a> Related</h2><ul><li><a href="/docs/gateway/doctor">Doctor</a></li><li><a href="/docs/gateway/troubleshooting">Gateway troubleshooting</a></li><li><a href="/docs/help/faq#where-does-opensoul-store-its-data">Where does OpenSoul store its data?</a></li></ul>`,72)])])}const g=s(n,[["render",t]]);export{u as __pageData,g as default};
